26897	/* Return true when canonicalization would replace already-sampled tokens.
26898	 *
26899	 * A DS4 session checkpoint is more than a token vector: the backend state also
26900	 * contains raw SWA rows, compressed KV rows, indexer rows, and compressor
26901	 * frontiers.  Replacing any part of the live tail requires restoring that whole
26902	 * frontier first.  Extending exactly at the live end is safe; rewriting behind
26903	 * it is not an in-place operation. */
26904	bool ds4_session_rewrite_requires_rebuild(int live_len, int canonical_len, int common) {
26905	    if (live_len < 0 || canonical_len < 0 || common < 0) return true;
26906	    if (common > live_len || common > canonical_len) return true;
26907	    return common < live_len;
26908	}
