23285	/* =========================================================================
23286	 * Session Snapshot Payloads.
23287	 * =========================================================================
23288	 *
23289	 * The server disk cache stores a high-level file header, then delegates the
23290	 * graph-specific payload below to the engine.  This payload is intentionally
23291	 * not mmaped: restoring a checkpoint copies bytes back into the already
23292	 * allocated Metal tensors, preserving the same live graph buffers used by
23293	 * normal prefill/decode.  The raw SWA cache is serialized as the last logical
23294	 * window only; suffix prefill writes its own raw rows before attention.  The
23295	 * compressed caches are serialized up to their live row counts because sparse
23296	 * attention may select rows from the whole prefix.
23297	 *
23298	 * The payload is model-specific rather than self-describing.  The fixed header
23299	 * records enough shape information to reject a file written for a different
23300	 * DS4 runtime, then the body writes: checkpoint tokens, last logits, per-layer
23301	 * compressed row counts, raw SWA rows in logical order, compressed attention
23302	 * rows, and the compressor/indexer frontiers.  That is the minimum state needed
23303	 * for the next token to match a session that had just prefetched the prefix.
23304	 */
23305	
23306	#define DS4_SESSION_IO_CHUNK (8u * 1024u * 1024u)
23307	
23308	static void payload_set_err(char *err, size_t errlen, const char *msg) {
23309	    if (errlen != 0) snprintf(err, errlen, "%s", msg);
23310	}
23311	
23312	static void payload_put_u32(uint8_t out[4], uint32_t v) {
23313	    out[0] = (uint8_t)(v);
23314	    out[1] = (uint8_t)(v >> 8);
23315	    out[2] = (uint8_t)(v >> 16);
23316	    out[3] = (uint8_t)(v >> 24);
23317	}
23318	
23319	static uint32_t payload_get_u32(const uint8_t in[4]) {
23320	    return (uint32_t)in[0] |
23321	           ((uint32_t)in[1] << 8) |
23322	           ((uint32_t)in[2] << 16) |
23323	           ((uint32_t)in[3] << 24);
23324	}
23325	
23326	static int payload_write_bytes(FILE *fp, const void *ptr, uint64_t bytes, char *err, size_t errlen) {
23327	    const uint8_t *p = ptr;
